// Parse OpenAI response
const response = $input.first().json.message?.content || $input.first().json.text || '';
const originalData = $('Parse Input').first().json;

let result;

// Check if response contains JSON (email command)
const jsonMatch = response.match(/```json\s*([\s\S]*?)\s*```/) || response.match(/\{[\s\S]*"type"\s*:\s*"email"[\s\S]*\}/);

if (jsonMatch) {
  try {
    const jsonStr = jsonMatch[1] || jsonMatch[0];
    const parsed = JSON.parse(jsonStr);

    if (parsed.type === 'email') {
      result = {
        type: 'email',
        recipients: parsed.recipients || [],
        recipientNames: parsed.recipientNames || parsed.recipients || [],
        subject: parsed.subject || 'Mensagem do Daher Plan',
        body: parsed.body || '',
        needsClarification: parsed.needsClarification || false,
        clarificationQuestion: parsed.clarificationQuestion || '',
        ...originalData
      };
    } else {
      result = {
        type: 'answer',
        message: response.replace(/```json[\s\S]*?```/g, '').trim(),
        ...originalData
      };
    }
  } catch (e) {
    result = {
      type: 'answer',
      message: response,
      ...originalData
    };
  }
} else {
  // Plain text response (question/answer)
  result = {
    type: 'answer',
    message: response,
    ...originalData
  };
}

return result;

