// Email sent successfully
const data = $('Parse Response').first().json;

return {
  success: true,
  type: 'email_sent',
  message: `✅ E-mail enviado com sucesso para: ${(data.recipientNames || data.recipients || []).join(', ')}.\n\nUma cópia foi enviada para você em ${data.userEmail}.`,
  timestamp: new Date().toISOString()
};

// Return clarification question
const data = $input.first().json;

return {
  success: true,
  type: 'clarification',
  message: data.clarificationQuestion || 'Poderia me dar mais detalhes sobre para quem você gostaria de enviar o e-mail?',
  timestamp: new Date().toISOString()
};

// Return answer response
const data = $input.first().json;

return {
  success: true,
  type: 'answer',
  message: data.message || 'Desculpe, não consegui processar sua pergunta.',
  timestamp: new Date().toISOString()
};

// Return error response
const data = $input.first().json;

return {
  success: false,
  type: 'error',
  message: data.errorMessage || 'Ocorreu um erro ao processar sua solicitação.',
  timestamp: new Date().toISOString()
};
